#include <bits/stdc++.h>
using namespace std;
int main(){
    string num;
    cin >> num;
    sort(num.rbegin(), num.rend());
    for(int i = num.size() - 1; i >= 0; i--){
        if((num[i] - '0') % 2 == 1){
            swap(num[0], num[i]);
            break;
        }
    }
    if(num[0] == '0' && num.size() > 1){
        sort(num.rbegin(), num.rend());
    }
    if((num[num.size() - 1] - '0') % 2 == 0){
        cout << -1 << endl;
    } else {
        cout << num << endl;
    }
    return 0;
}
